# @workspace/api-client

A TypeScript client for interacting with the Anedot API, built on top of React Query.

## Features

### ApiClient

The base client for making API requests:

```typescript
import { ApiClient } from "@workspace/api-client";

const client = new ApiClient({
  namespace: "org", // "admin" | "org" | "public" | "user"
  performRedirect: true,
});

// Methods
await client.get<T>(url);
await client.post<T>(url, body);
await client.put<T>(url, body);
await client.patch<T>(url, body);
await client.delete<T>(url);
```

### Key Factory

Query keys are now generated using the `createResourceKeys` function. This helper function creates a type-safe object containing query key generators for entity and list operations. It takes a base resource key string and an object defining the key generation logic for each operation type. The generated keys automatically include the resource type in the return array.

They keys are generated in the following order:

```
[namespace, "accounts", accountId, resourceKey, resourceId, resourceType, parameters];
```

- `namespace` is defaulted to 'org', if not provided.
- The `"accounts"` segment and `accountId` are only included in the query key when an accountId parameter is provided.
- Parameters are included as an object (this means they are all considered equal in heirachy)

```typescript
import { generateQueryKey } from "@workspace/api-client/cacheHelper";

const resourceKeys = createResourceKeys("donations", {
  entity: (params) => ({
    queryKey: generateQueryKey(params),
  }),
  list: (params) => ({
    queryKey: generateQueryKey(params),
  }),
});
```

```typescript
resourceKeys.entity({
  accountId: "12345",
  resourceId: "000001",
  parameters: { status: "processed" },
}).queryKey;

Result: ["org", "accounts", "12345", "donations", "000001", "entity", { status: "processed" }];
```

### React Query Hooks

[All hooks include the standard return props from React Query](https://tanstack.com/query/latest/docs/framework/react/reference/useQuery) (ex. `isLoading`, `isFetching`, `isSuccess`, `status`, `error`, etc)

#### useGetOne

Fetch a single resource:

```typescript
import { useGetOne } from "@workspace/api-client"

const { data, isLoading, error } = useGetOne<ResourceType>(
  path: string,
  params: Params,
  queryKey: queryKeys.entity({ accountId, resourceId }),
  options?: {
    namespace?: 'admin' | 'org' | 'public' | 'user'; // defaults to "org"
    performRedirect?: boolean;
    resourceKey?: string;
  }
);
```

#### useGetList

Fetch a paginated list of resources:

```typescript
import { useGetList } from "@workspace/api-client"

const { data, isLoading, error } = useGetList<ResourceType>(
  path: string,
  params: Params & UseGetPageParams,
  queryKey: queryKeys.list({ accountId, resourceId }),
  options?: {
    namespace?: "admin" | "org" | "public" | "user"; // defaults to "org"
    performRedirect?: boolean;
  }
);

// data will be typed as:
// {
//   data: ResourceType[],
//   meta: {
//     currentPage: number,
//     totalCount: number,
//     totalPages: number
//   }
// }
```

#### useGetInfinite

Fetch an infinite list of resources with cursor-based pagination:

```typescript
import { useGetInfinite } from "@workspace/api-client"

const {
  data,
  isLoading,
  error,
  fetchNextPage,
  hasNextPage,
  isFetchingNextPage
} = useGetInfinite<ResourceType>(
  path: string,
  params: Params & UseGetPageParams,
  queryKey: queryKeys.list({ accountId, resourceId }),
  options?: {
    namespace?: "admin" | "org" | "public" | "user"; // defaults to "org"
    performRedirect?: boolean;
  }
);
```

Note: All query hooks default to using the "org" namespace if not specified. This means you only need to specify the namespace if you want to use a different one (admin, public, or user).

## Cache Management

#### useCacheHelper

Helper hook for managing query cache:

```typescript
import { useCacheHelper } from "@workspace/api-client/query-helpers";
import { donationQueryKeys } from "@state/donations";

const { refreshCache } = useCacheHelper();

// Example: Refreshing a single query
const handleDonationUpdate = async (donation: Donation) => {
  // After updating a donation
  await refreshCache([donationQueryKeys.entity({ accountId, resourceId: donation.id })]);
};

// Example: Refreshing queries manually
const handleResourceUpdate = async (resourceType: string) => {
  await refreshCache([
    ["org", "accounts", "12345"], // invalidation all queries under the account
    ["org", "accounts", "12345", "donations", "02468", "entity"], // specific donation invalidation
  ]);
};
```

Double check that the query key generated here is the same as it is generated in the

### Shared Hooks

#### useGetMe

A hook for fetching the current user is provided:

```typescript
import { useGetMe } from "@workspace/api-client/user"

const { data: user, isLoading, error } = useGetMe({
  accountId?: string;
  enabled?: boolean;
  performRedirect?: boolean;
});
```

## Installation

```bash
npm install @workspace/api-client
# or
yarn add @workspace/api-client
```

## Environment Variables

Required environment variables:

- `VITE_API_HOSTNAME`: The base URL for the API

