export class ApiError extends Error {
  response?: AxiosError<ClientErrorResponse>["response"];

  type: ApiClientErrorTypes;

  constructor(
    message: string,
    type: ApiClientErrorTypes,
    response?: AxiosError<ClientErrorResponse>["response"],
  ) {
    super(message);
    this.type = type;
    this.response = response;
  }
}

const deserializeError = (error: unknown): ApiError => {
  // When we get a network error it's this specific message by axios
  // See more: https://github.com/axios/axios/issues/383
  if (
    ["Network Error", "Network error"].includes(
      (error as { message: string }).message,
    )
  ) {
    return new ApiError(
      "A network error occurred.",
      ApiClientErrorTypes.Network,
    );
  }

  if (axios.isAxiosError(error)) {
    const axiosError = error as AxiosError<ClientErrorResponse>;
    const data = axiosError.response?.data;

    // Try to construct a more informative error message
    let errorMessage = data?.message;

    // If no message, try to extract from errors array (typical 422 validation errors)
    if (!errorMessage && data?.errors && data.errors.length > 0) {
      // Collect all error details from all error objects
      const allDetails = data.errors.flatMap((err) => err.details || []);
      if (allDetails.length > 0) {
        errorMessage = allDetails.join(" ");
      }
    }

    if (!errorMessage) {
      const status = axiosError.response?.status;
      const statusText = axiosError.response?.statusText;
      const axiosMessage = axiosError.message;
      const code = axiosError.code;

      // Build a descriptive error message from available information
      const parts: string[] = [];

      if (status) {
        parts.push(`HTTP ${status}`);
        if (statusText) {
          parts.push(statusText);
        }
      }

      if (code && code !== "ERR_BAD_REQUEST" && code !== "ERR_BAD_RESPONSE") {
        parts.push(`(${code})`);
      }

      if (
        axiosMessage &&
        axiosMessage !== `Request failed with status code ${status}`
      ) {
        parts.push(axiosMessage);
      }

      errorMessage =
        parts.length > 0 ? parts.join(" - ") : "An axios error has occurred.";
    }

    return new ApiError(
      errorMessage,
      ApiClientErrorTypes.Axios,
      error.response,
    );
  }

  return new ApiError(
    "An unknown error occurred.",
    ApiClientErrorTypes.Unknown,
  );
};

