  constructor({
    baseURL,
    namespace = "org",
    performRedirect = true,
  }: ApiClientParams = {}) {
    this.defaultNamespace = namespace;
    const effectiveBaseURL = baseURL ?? `${getApiHostname()}/${namespace}/v3`;

    this.client = axios.create({
      baseURL: effectiveBaseURL,
      headers: {
        Accept: "application/json",
        "Content-Type": "application/json",
        "X-APP": "anedot:3",
        "X-Requested-With": "XMLHttpRequest",
      },
      withCredentials: true,
      xsrfCookieName: "_anedot_session",
      xsrfHeaderName: "X-CSRF-TOKEN",
    });

    this.client.interceptors.response.use(
      (response: AxiosResponse<CsrfResponse>) => {
        if (response.data.csrfToken) {
          setSharedCsrfToken(response.data.csrfToken);
        }
        return response;
      },
      (error: AxiosError) => {
        if (error.response?.status === 401 && Boolean(performRedirect)) {
          const redirectParams = new URLSearchParams({
            return_to: window.location.href,
          });
          window.location.assign(
            `${getApiHostname()}/${LOGIN_PATH}?${redirectParams.toString()}`,
          );
        }
        throw error;
      },
    );

    this.client.interceptors.request.use((config) => {
      const csrfToken = getSharedCsrfToken();
      if (csrfToken) {
        config.headers["X-CSRF-Token"] = csrfToken;
      }
      return config;
    });
  }

