import type { QueryKeyParams } from "../types/query";
import { isTruthy } from "../utils/isTruthy";
import { removeEmpty } from "../utils/removeEmpty";

type KeyElement =
  | Record<string, Record<string, string> | string | null | undefined>
  | string;

export type GeneratedQueryKey = readonly KeyElement[];

export const generateQueryKey = ({
  accountId,
  namespace = "org",
  parameters,
  resourceId,
  resourceKey,
  resourceType,
}: QueryKeyParams) => {
  return [
    namespace,
    ...(accountId ? ["accounts", accountId] : []),
    resourceKey,
    resourceId,
    resourceType,
    removeEmpty(parameters),
  ].filter(isTruthy);
