/**
 * Creates a resource keys object that can be used to generate query keys for a resource.
 * Automatically adds the resource type (entity or list) to the resulting query key.
 * @param keyGenerators - The key generators for the resource.
 * @returns A resource keys object.
 *
 * @example
 * ```ts
 * const resourceKeys = createResourceKeys({
 *   entity: (params) => ({
 *     queryKey: generateQueryKey({ ...params, resourceKey: userResourceKeys.entity }),
 *   }),
 *   list: (params) => ({
 *     queryKey: generateQueryKey({ ...params, resourceKey: userResourceKeys.list }),
 *   }),
 * });
 * ```
 */

type ResourceKeyGenerators = {
  entity?: (
    params: Omit<QueryKeyParams, "resourceType"> & { resourceType: "entity" },
  ) => {
    queryKey: GeneratedQueryKey;
  };
  list?: (
    params: Omit<QueryKeyParams, "resourceType"> & { resourceType: "list" },
  ) => {
    queryKey: GeneratedQueryKey;
  };
};

// Return type will only include the keys that were provided
type ResourceKeys<T extends ResourceKeyGenerators> = {
  [K in keyof T as T[K] extends undefined ? never : K]: (
    params: Omit<QueryKeyParams, "resourceType">,
  ) => { queryKey: GeneratedQueryKey };
};

export const createResourceKeys = <T extends ResourceKeyGenerators>(
  resourceKey: string,
  keyGenerators: T,
): ResourceKeys<T> => {
  return {
    ...(keyGenerators.entity
      ? {
          entity: (params: Omit<QueryKeyParams, "resourceType">) =>
            keyGenerators.entity?.({
              ...params,
              resourceKey: params.resourceKey ?? resourceKey,
              resourceType: "entity",
            }),
        }
      : {}),
    ...(keyGenerators.list
      ? {
          list: (params: Omit<QueryKeyParams, "resourceType">) =>
            keyGenerators.list?.({
              ...params,
              resourceKey: params.resourceKey ?? resourceKey,
              resourceType: "list",
            }),
        }
      : {}),
  } as ResourceKeys<T>;
};

